import { createContext, useContext, useState } from 'react';
import axios from 'axios'; // Siguraduhing naka-install ang axios

const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(JSON.parse(localStorage.getItem('user')) || null);

  // Ginawa nating async para makapag-wait sa API response
  const login = async (email, password) => {
    try {
      // Palitan mo ito ng tamang API endpoint mo
      const response = await axios.post('http://localhost:5000/api/login', { email, password });
      
      const userData = response.data; // Dito galing yung { email, role, etc. }
      
      setUser(userData);
      localStorage.setItem('user', JSON.stringify(userData));
      
      return userData; // Importante itong return para makuha ng LoginPage
    } catch (error) {
      // I-throw ang error para mahuli ng 'catch' block sa LoginPage
      throw error;
    }
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('user');
  };

  return (
    <AuthContext.Provider value={{ user, setUser, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => useContext(AuthContext);
